const staticData = $getWorkflowStaticData('global');
const resposta = $input.first().json;
const init = $('Init Pagar').first().json;

const registros = resposta.conta_pagar_cadastro || [];
staticData.pagar.push(...registros);

const paginaAtual = resposta.pagina || 1;
const totalPaginas = resposta.total_de_paginas || 1;

console.log('Pagar - Pag ' + paginaAtual + '/' + totalPaginas + ' | +' + registros.length + ' | Total: ' + staticData.pagar.length);

return [{
  json: {
    pagina: paginaAtual + 1,
    registros_por_pagina: init.registros_por_pagina,
    app_key: init.app_key,
    app_secret: init.app_secret,
    endpoint: init.endpoint,
    call: init.call,
    tem_mais: paginaAtual < totalPaginas
  }
}];

const staticData = $getWorkflowStaticData('global');
const registros = staticData.pagar || [];

console.log('Flatten Pagar: ' + registros.length + ' registros para CSV');

if (registros.length === 0) {
  return [{ json: { info: 'Nenhuma conta a pagar encontrada', total: 0 } }];
}

return registros.map(reg => {
  const cat = (reg.categorias && reg.categorias[0]) || {};
  const dist = (reg.distribuicao && reg.distribuicao[0]) || {};

  return {
    json: {
      codigo_lancamento_omie: reg.codigo_lancamento_omie || '',
      codigo_lancamento_integracao: reg.codigo_lancamento_integracao || '',
      codigo_cliente_fornecedor: reg.codigo_cliente_fornecedor || '',
      data_vencimento: reg.data_vencimento || '',
      data_emissao: reg.data_emissao || '',
      data_entrada: reg.data_entrada || '',
      data_previsao: reg.data_previsao || '',
      valor_documento: reg.valor_documento || 0,
      valor_titulo: reg.valor_titulo || 0,
      codigo_categoria: reg.codigo_categoria || cat.codigo_categoria || '',
      status_titulo: reg.status_titulo || '',
      codigo_tipo_documento: reg.codigo_tipo_documento || '',
      numero_documento: reg.numero_documento || '',
      numero_parcela: reg.numero_parcela || '',
      observacao: reg.observacao || '',
      id_conta_corrente: reg.id_conta_corrente || '',
      bloqueado: reg.bloqueado || '',
      baixa_bloqueada: reg.baixa_bloqueada || '',
      operacao: reg.operacao || '',
      valor_pis: dist.valor_pis || 0,
      valor_cofins: dist.valor_cofins || 0,
      valor_csll: dist.valor_csll || 0,
      valor_icms: dist.valor_icms || 0,
      valor_iss: dist.valor_iss || 0
    }
  };
});

